/**
 * @summary OAuth callback handler
 */
export const getOauthCallbackUrl = (params?: OauthCallbackParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/integrations/oauth/callback?${stringifiedParams}`
    : `/api/integrations/oauth/callback`;
};

export const oauthCallback = async (
  params?: OauthCallbackParams,
  options?: RequestInit,
): Promise<unknown> => {
  return customFetch<unknown>(getOauthCallbackUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getOauthCallbackQueryKey = (params?: OauthCallbackParams) => {
  return [
    `/api/integrations/oauth/callback`,
    ...(params ? [params] : []),
  ] as const;
};

export const getOauthCallbackQueryOptions = <
  TData = Awaited<ReturnType<typeof oauthCallback>>,
  TError = ErrorType<void>,
>(
  params?: OauthCallbackParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof oauthCallback>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getOauthCallbackQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof oauthCallback>>> = ({
    signal,
  }) => oauthCallback(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof oauthCallback>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type OauthCallbackQueryResult = NonNullable<
  Awaited<ReturnType<typeof oauthCallback>>
>;
export type OauthCallbackQueryError = ErrorType<void>;

/**
 * @summary OAuth callback handler
 */

export function useOauthCallback<
  TData = Awaited<ReturnType<typeof oauthCallback>>,
  TError = ErrorType<void>,
>(
  params?: OauthCallbackParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof oauthCallback>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getOauthCallbackQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

